import React from 'react';
import Marquee from "react-fast-marquee";

const logos = [
    { alt: "Vercel", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/vercel.svg" },
    { alt: "GitHub", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/github.svg" },
    { alt: "GitLab", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/gitlab.svg" },
    { alt: "Google Cloud", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/googlecloud.svg" },
    { alt: "JetBrains", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/jetbrains.svg" },
    { alt: "Netlify", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/netlify.svg" },
    { alt: "DigitalOcean", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/digitalocean.svg" },
    { alt: "Cloudflare", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/cloudflare.svg" },
    { alt: "Stripe", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/stripe.svg" },
    { alt: "Docker", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/docker.svg" },
    { alt: "Kubernetes", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/kubernetes.svg" },
    { alt: "PostgreSQL", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/postgresql.svg" },
    { alt: "MongoDB", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/mongodb.svg" },
    { alt: "Sentry", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/sentry.svg" },
];

const LogoMarquee = () => {
    return (
        <section aria-label="Trusted by" style={{
            padding: '60px 0',
            background: 'linear-gradient(135deg, #f8f9fa 0%, #e9ecef 100%)',
            borderTop: '1px solid #dee2e6',
            borderBottom: '1px solid #dee2e6',
            position: 'relative',
            overflow: 'hidden'
        }}>
            <div style={{
                maxWidth: '1200px',
                margin: '0 auto',
                padding: '0 20px'
            }}>
                <div style={{ textAlign: 'center', marginBottom: '40px' }}>
                    <p style={{
                        fontSize: '14px',
                        fontWeight: '600',
                        textTransform: 'uppercase',
                        letterSpacing: '0.1em',
                        color: '#6c757d',
                        marginBottom: '10px'
                    }}>
                        Trusted by top engineering teams
                    </p>
                    <h2 style={{
                        fontSize: '32px',
                        fontWeight: '700',
                        color: '#2c3e50',
                        marginBottom: '20px'
                    }}>
                        Industry Leaders Choose Sky States
                    </h2>
                    <p style={{
                        fontSize: '16px',
                        color: '#6c757d',
                        maxWidth: '600px',
                        margin: '0 auto'
                    }}>
                        Join thousands of professionals from leading companies who have transformed their careers with our programs
                    </p>
                </div>

                {/* First Marquee Row */}
                <div style={{
                    position: 'relative',
                    marginBottom: '30px'
                }}>
                    <Marquee 
                        gradient={true}
                        gradientColor={[248, 249, 250]}
                        gradientWidth={100}
                        speed={40}
                        pauseOnHover={true}
                        loop={0}
                        play={true}
                    >
                        {logos.map((logo, idx) => (
                            <div
                                key={`${logo.alt}-${idx}`}
                                style={{
                                    display: 'inline-flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    margin: '0 40px',
                                    padding: '20px',
                                    background: 'white',
                                    borderRadius: '12px',
                                    boxShadow: '0 4px 20px rgba(0, 0, 0, 0.08)',
                                    transition: 'all 0.3s ease',
                                    cursor: 'pointer',
                                    minWidth: '120px',
                                    height: '80px'
                                }}
                                onMouseEnter={(e) => {
                                    e.currentTarget.style.transform = 'translateY(-5px) scale(1.05)';
                                    e.currentTarget.style.boxShadow = '0 8px 30px rgba(0, 0, 0, 0.15)';
                                }}
                                onMouseLeave={(e) => {
                                    e.currentTarget.style.transform = 'translateY(0) scale(1)';
                                    e.currentTarget.style.boxShadow = '0 4px 20px rgba(0, 0, 0, 0.08)';
                                }}
                            >
                                <img
                                    src={logo.src}
                                    alt={logo.alt}
                                    style={{
                                        height: '40px',
                                        width: 'auto',
                                        filter: 'grayscale(100%)',
                                        opacity: '0.7',
                                        transition: 'all 0.3s ease'
                                    }}
                                    onMouseEnter={(e) => {
                                        e.target.style.filter = 'grayscale(0%)';
                                        e.target.style.opacity = '1';
                                    }}
                                    onMouseLeave={(e) => {
                                        e.target.style.filter = 'grayscale(100%)';
                                        e.target.style.opacity = '0.7';
                                    }}
                                    loading="lazy"
                                />
                            </div>
                        ))}
                    </Marquee>
                </div>

                {/* Second Marquee Row (Reverse) */}
                <div style={{
                    position: 'relative'
                }}>
                    <Marquee 
                        gradient={true}
                        gradientColor={[248, 249, 250]}
                        gradientWidth={100}
                        speed={35}
                        pauseOnHover={true}
                        loop={0}
                        play={true}
                        direction="right"
                    >
                        {[...logos].reverse().map((logo, idx) => (
                            <div
                                key={`${logo.alt}-reverse-${idx}`}
                                style={{
                                    display: 'inline-flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    margin: '0 40px',
                                    padding: '20px',
                                    background: 'white',
                                    borderRadius: '12px',
                                    boxShadow: '0 4px 20px rgba(0, 0, 0, 0.08)',
                                    transition: 'all 0.3s ease',
                                    cursor: 'pointer',
                                    minWidth: '120px',
                                    height: '80px'
                                }}
                                onMouseEnter={(e) => {
                                    e.currentTarget.style.transform = 'translateY(-5px) scale(1.05)';
                                    e.currentTarget.style.boxShadow = '0 8px 30px rgba(0, 0, 0, 0.15)';
                                }}
                                onMouseLeave={(e) => {
                                    e.currentTarget.style.transform = 'translateY(0) scale(1)';
                                    e.currentTarget.style.boxShadow = '0 4px 20px rgba(0, 0, 0, 0.08)';
                                }}
                            >
                                <img
                                    src={logo.src}
                                    alt={logo.alt}
                                    style={{
                                        height: '40px',
                                        width: 'auto',
                                        filter: 'grayscale(100%)',
                                        opacity: '0.7',
                                        transition: 'all 0.3s ease'
                                    }}
                                    onMouseEnter={(e) => {
                                        e.target.style.filter = 'grayscale(0%)';
                                        e.target.style.opacity = '1';
                                    }}
                                    onMouseLeave={(e) => {
                                        e.target.style.filter = 'grayscale(100%)';
                                        e.target.style.opacity = '0.7';
                                    }}
                                    loading="lazy"
                                />
                            </div>
                        ))}
                    </Marquee>
                </div>

                {/* Stats Section */}
                <div style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                    gap: '30px',
                    marginTop: '60px',
                    textAlign: 'center'
                }}>
                    <div style={{
                        padding: '30px',
                        background: 'white',
                        borderRadius: '16px',
                        boxShadow: '0 8px 30px rgba(0, 0, 0, 0.1)'
                    }}>
                        <div style={{
                            fontSize: '48px',
                            fontWeight: '700',
                            color: '#28a745',
                            marginBottom: '10px'
                        }}>
                            15+
                        </div>
                        <div style={{
                            fontSize: '16px',
                            color: '#6c757d',
                            fontWeight: '500'
                        }}>
                            Industry Partners
                        </div>
                    </div>
                    <div style={{
                        padding: '30px',
                        background: 'white',
                        borderRadius: '16px',
                        boxShadow: '0 8px 30px rgba(0, 0, 0, 0.1)'
                    }}>
                        <div style={{
                            fontSize: '48px',
                            fontWeight: '700',
                            color: '#007bff',
                            marginBottom: '10px'
                        }}>
                            5000+
                        </div>
                        <div style={{
                            fontSize: '16px',
                            color: '#6c757d',
                            fontWeight: '500'
                        }}>
                            Professionals Trained
                        </div>
                    </div>
                    <div style={{
                        padding: '30px',
                        background: 'white',
                        borderRadius: '16px',
                        boxShadow: '0 8px 30px rgba(0, 0, 0, 0.1)'
                    }}>
                        <div style={{
                            fontSize: '48px',
                            fontWeight: '700',
                            color: '#e74c3c',
                            marginBottom: '10px'
                        }}>
                            95%
                        </div>
                        <div style={{
                            fontSize: '16px',
                            color: '#6c757d',
                            fontWeight: '500'
                        }}>
                            Success Rate
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default LogoMarquee;
